use clap::{Parser, Subcommand};

const VERSION: &str = env!("CARGO_PKG_VERSION");

#[derive(Parser)]
#[command(name = "tidy-claude", version = VERSION, about = "Backup, sync, and clean up Claude Code configuration")]
struct Cli {
    /// Enable debug output
    #[arg(long, global = true)]
    debug: bool,

    #[command(subcommand)]
    command: Option<Commands>,
}

#[derive(Subcommand)]
enum Commands {
    /// Sync configuration: pull, restore, backup, push
    Sync,
    /// Show or update configuration
    Config {
        /// Set the backup data directory
        #[arg(long)]
        data_dir: Option<String>,
        /// Set the git remote URL for backups
        #[arg(long)]
        remote_backup: Option<String>,
    },
    /// Clean up old conversation logs and session files
    Cleanup {
        /// Delete sessions older than N days (default: 7)
        #[arg(long, default_value_t = 7)]
        older_than: u32,
        /// Skip interactive menu, clean all projects
        #[arg(short, long)]
        all: bool,
        /// Preview deletions without removing
        #[arg(long)]
        dry_run: bool,
        /// Include user-named sessions in cleanup
        #[arg(long)]
        with_named_sessions: bool,
    },
    /// Show git status of the backup repository
    Status,
}

pub fn run() {
    let cli = Cli::parse();

    match cli.command {
        None | Some(Commands::Sync) => {
            println!("sync: not yet implemented (Phase 5)");
        }
        Some(Commands::Config { data_dir, remote_backup }) => {
            println!("config: data_dir={data_dir:?}, remote_backup={remote_backup:?} (Phase 5)");
        }
        Some(Commands::Cleanup { older_than, all, dry_run, with_named_sessions }) => {
            println!("cleanup: older_than={older_than}, all={all}, dry_run={dry_run}, with_named_sessions={with_named_sessions} (Phase 5)");
        }
        Some(Commands::Status) => {
            println!("status: not yet implemented (Phase 5)");
        }
    }
}

